import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { map, shareReplay } from 'rxjs/operators';
import { PublicAuction } from '../interfaces/auction.interface';
import { generatedDataUrl } from './generated-data-url';

@Injectable({
  providedIn: 'root'
})
export class AuctionPublicService {
  private readonly auctions$: Observable<PublicAuction[]>;

  constructor(private readonly http: HttpClient) {
    this.auctions$ = this.http
      .get<PublicAuction[]>(generatedDataUrl('auctions.json'))
      .pipe(shareReplay(1));
  }

  getAuctions(): Observable<PublicAuction[]> {
    return this.auctions$;
  }

  getAuctionBySlug(slug: string): Observable<PublicAuction | undefined> {
    return this.auctions$.pipe(
      map((auctions) => auctions.find((auction) => auction.slug === slug))
    );
  }
}
